// Parse incoming leads + service info
const input = $input.item.json;
let data = input.body || input;
if (typeof data === 'string') data = JSON.parse(data);

const leads = data.leads || [];
const service = data.service || 'IT Services';
const tone = data.tone || 'professional';
const additionalContext = data.additional_context || '';

console.log(`Processing ${leads.length} leads for ${service} outreach`);

// Output one item per lead so we can process each individually
const items = leads.map(lead => ({
  json: {
    ...lead,
    service,
    tone,
    additional_context: additionalContext
  }
}));

return items;

