// Parse the AI output to extract subject and body
const output = $json.output;
const lead = $('Parse Leads Input').item.json;

let emailData;
try {
  // Try to parse JSON directly
  const jsonMatch = output.match(/\{[\s\S]*\}/);
  emailData = JSON.parse(jsonMatch ? jsonMatch[0] : output);
} catch (e) {
  // Fallback: extract manually
  emailData = {
    matched_service: 'IT Services',
    subject: `IT Solutions for ${lead.company_name}`,
    body: output
  };
}

return [{
  json: {
    lead_id: lead.id,
    to_email: lead.email,
    to_name: `${lead.first_name} ${lead.last_name}`,
    company: lead.company_name,
    subject: emailData.subject,
    body: emailData.body,
    service: emailData.matched_service || 'IT Services'
  }
}];
